// services/api-gateway/index.js — minimal iskelet
const express = require('express');
const { createProxyMiddleware } = require('http-proxy-middleware');
const app = express();

// Docker Compose network'ünde host adı = service adı
app.use('/api/users',    createProxyMiddleware({ target: 'http://user-service:3001',    changeOrigin: true, pathRewrite: {'^/api/users': '/users'} }));
app.use('/api/products', createProxyMiddleware({ target: 'http://product-service:3002', changeOrigin: true, pathRewrite: {'^/api/products': '/products'} }));
app.use('/api/orders',   createProxyMiddleware({ target: 'http://order-service:3003',   changeOrigin: true, pathRewrite: {'^/api/orders': '/orders'} }));

app.get('/health', (_, res) => res.json({ status: 'ok' }));
app.listen(3000);
